@@ -1,0 +1,126 @@
+@page "/board"
+@rendermode InteractiveServer
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h3 class="mb-3">Project Board</h3>
+
+@if (isLoading)
+{
+    <div class="d-flex justify-content-center p-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error loading tasks:</strong> @errorMessage
+        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
+    </div>
+}
+else
+{
+    <BoardStats Tasks="tasks" />
+    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />
+
+    <div class="row g-3">
+        @for (var i = 0; i < columns.Length; i++)
+        {
+            var column = columns[i];
+            var columnTasks = FilteredTasksForStatus(column);
+            var colIndex = i;
+
+            <KanbanColumn ColumnName="@column"
+                          Tasks="columnTasks"
+                          IsFirst="colIndex == 0"
+                          IsLast="colIndex == columns.Length - 1"
+                          OnMoveLeft="id => MoveTask(id, colIndex - 1)"
+                          OnMoveRight="id => MoveTask(id, colIndex + 1)"
+                          OnTaskCreated="HandleTaskCreated" />
+        }
+    </div>
+}
+
+@code {
+    private static readonly string[] columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> tasks = [];
+    private string searchText = "";
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        isLoading = true;
+        errorMessage = null;
+        try
+        {
+            tasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private List<TaskItem> FilteredTasksForStatus(string status)
+    {
+        return tasks
+            .Where(t => t.Status == status)
+            .Where(t => string.IsNullOrWhiteSpace(searchText)
+                || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
+            .ToList();
+    }
+
+    private void HandleSearchChanged(string text)
+    {
+        searchText = text;
+    }
+
+    private async Task MoveTask(int taskId, int targetColumnIndex)
+    {
+        if (targetColumnIndex < 0 || targetColumnIndex >= columns.Length)
+            return;
+
+        var newStatus = columns[targetColumnIndex];
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var existing = tasks.FirstOrDefault(t => t.Id == taskId);
+            if (existing is not null)
+            {
+                tasks[tasks.IndexOf(existing)] = existing with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+
+    private async Task HandleTaskCreated(TaskItem draft)
+    {
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(draft.Title, draft.Assignee, draft.Priority, draft.DueDate);
+            tasks.Add(created);
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+}
+

